```python
def most_frequent_word(text):
    words = text.lower().split()
    counts = {}
    order = []
    for w in words:
        if w not in counts:
            counts[w] = 0
            order.append(w)
        counts[w] += 1
    best = order[0]
    for w in order:
        if counts[w] > counts[best]:
            best = w
    return best
```

```python
def wrap_text(s, width):
    words = s.split()
    lines = []
    current = ""
    for w in words:
        if not current:
            current = w
        elif len(current) + 1 + len(w) <= width:
            current += " " + w
        else:
            lines.append(current)
            current = w
    if current:
        lines.append(current)
    return lines
```

