def percentile(data, q):
    if not data:
        raise ValueError("empty data")
    s = sorted(data)
    if len(s) == 1:
        return float(s[0])
    rank = (q / 100) * (len(s) - 1)
    lo = int(rank)
    frac = rank - lo
    if lo + 1 < len(s):
        return s[lo] + frac * (s[lo + 1] - s[lo])
    return float(s[lo])
