```js
function movingAverage(arr, windowSize) {
  if (windowSize <= 0) return [];
  const result = [];
  for (let i = 0; i + windowSize <= arr.length; i++) {
    const window = arr.slice(i, i + windowSize);
    const sum = window.reduce((a, b) => a + b, 0);
    result.push(sum / windowSize);
  }
  return result;
}
```

