def parse_ini(text):
    result = {}
    section = None
    for raw in text.splitlines():
        line = raw.strip()
        if not line or line[0] in ';#':
            continue
        if line.startswith('[') and line.endswith(']'):
            section = line[1:-1].strip()
            result[section] = {}
        elif '=' in line:
            key, value = line.split('=', 1)
            result[section][key.strip()] = value.strip()
    return result
```

