```python
def bsearch(arr, target):
    def rec(lo, hi):
        if lo > hi:
            return -1
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        if arr[mid] < target:
            return rec(mid + 1, hi)
        return rec(lo, mid - 1)
    return rec(0, len(arr) - 1)
```

